async function evaluateCandidate( candidateName, candidateInfo, jobDescription, externalUserId ) { console.log(`Evaluating ${candidateName}...`); console.log("=".repeat(50)); // Step 1: Submit task console.log(`
1. Submitting task...`); const task = await submitTask( "recruitment_v1", `Screen ${candidateName}`, "Evaluate candidate fit", externalUserId, `Job: ${jobDescription}

Candidate: ${candidateInfo}`, "Score (0-100) and recommendation (PASS/MAYBE/REJECT)" ); console.log(` ✓ Task ID: ${task.task_id}`); // Step 2: Poll for result console.log(`
2. Waiting for result...`); const finalTask = await pollTaskStatus("recruitment_v1", task.task_id); // Step 3: Process result console.log(`
3. Result:`); console.log(` Status: ${finalTask.status}`); if (finalTask.status === 'done') { const result = finalTask.result; console.log(` Score: ${result.overall_score}/100`); console.log(` Decision: ${result.decision}`); console.log(` Reasoning: ${result.reasoning}`); } else if (finalTask.status === 'failed') { console.log(` Error: ${finalTask.result.error}`); } console.log("=".repeat(50)); return finalTask; } // Usage try { const result = await evaluateCandidate( "Alice Johnson", "7 years Python, 3 years Docker, 2 years Kubernetes", "Senior Backend Engineer - 5+ years required", "ceonova-user-456" ); } catch (error) { console.error("Evaluation failed:", error); }

async function evaluateCandidatesParallel( candidates, jobDescription, externalUserId ) { console.log(`Evaluating ${candidates.length} candidates in parallel...`); console.log("=".repeat(50)); // Step 1: Submit all tasks console.log(`
1. Submitting ${candidates.length} tasks...`); const submitPromises = candidates.map(candidate => submitTask( "recruitment_v1", `Screen ${candidate.name}`, "Evaluate fit", externalUserId, `Job: ${jobDescription}

Candidate: ${candidate.info}` ).then(task => ({ candidate: candidate.name, taskId: task.task_id })) ); const submitted = await Promise.all(submitPromises); console.log(` ✓ All ${submitted.length} tasks submitted!`); // Step 2: Poll all tasks console.log(`
2. Polling results...`); const pollPromises = submitted.map(({ candidate, taskId }) => pollTaskStatus("recruitment_v1", taskId) .then(task => ({ candidate, taskId, status: task.status, result: task.result })) .catch(error => ({ candidate, taskId, status: "error", error: error.message })) ); const results = await Promise.all(pollPromises); // Step 3: Display results console.log(`
${"=".repeat(50)}`); console.log("RESULTS:"); console.log("=".repeat(50)); results.forEach(result => { if (result.status === 'done') { const r = result.result; console.log(`✓ ${result.candidate}: ${r.overall_score}/100 - ${r.decision}`); } else if (result.status === 'error') { console.log(`✗ ${result.candidate}: ERROR - ${result.error}`); } else { console.log(`? ${result.candidate}: ${result.status}`); } }); return results; } // Usage const candidates = [ { name: "Alice Johnson", info: "7 yrs Python, 3 yrs Docker" }, { name: "Bob Smith", info: "5 yrs Python, 1 yr Kubernetes" }, { name: "Carol White", info: "10 yrs backend, AWS expert" } ]; try { const results = await evaluateCandidatesParallel( candidates, "Senior Backend Engineer - 5+ years Python required", "ceonova-team-1" ); } catch (error) { console.error("Batch evaluation failed:", error); }
